import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [employee, setEmployee] = useState({
    firstName: "",
    lastName: "",
    empId: "",
    gender: "",
    dob: "",
    maritalStatus: "",
    email: "",

    // NEW
    aadhar: "",
    pan: "",

    designation: "",
    department: "",
    salary: "",
    role: "",

    skills: [],
    tempSkill: "",
    customSkill: "",

    bankName: "",
    accountNumber: "",
    ifsc: "",

    qualification: "",
    university: "",
    passingYear: "",

    employeeFiles: [],
    certificates: []
  });

  const skillOptions = [
    "C","C++","Java","Advanced Java","Python",
    "NodeJS","React","Angular","MongoDB"
  ];

  /* LOAD DESIGNATIONS */
  const [designations, setDesignations] = useState([]);
  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("designations")) || [];
    setDesignations(saved);
  }, []);

  /* LOAD EMPLOYEE */
  useEffect(() => {
    if (!isEditMode) return;

    const employees = JSON.parse(localStorage.getItem("employees")) || [];
    const found = employees.find(e => String(e.id) === String(id));

    if (found) {
      setEmployee(found);
    }
  }, [id,isEditMode]);

  /* INPUT CHANGE */
  const handleChange = (e) => {
    setEmployee({
      ...employee,
      [e.target.name]: e.target.value
    });
  };

  /* FILE UPLOAD */
  const handleFileUpload = (e, field) => {

    const files = Array.from(e.target.files);

    const converted = files.map(file => ({
      name: file.name,
      size: file.size,
      type: file.type,
      data: URL.createObjectURL(file)
    }));

    setEmployee(prev => ({
      ...prev,
      [field]: [...prev[field], ...converted]
    }));
  };

  /* SKILLS */
  const addSkill = () => {
    let newSkill = "";

    if (employee.tempSkill === "Other") {
      if (!employee.customSkill.trim()) return;
      newSkill = employee.customSkill.trim();
    } else {
      if (!employee.tempSkill) return;
      newSkill = employee.tempSkill;
    }

    if (!employee.skills.includes(newSkill)) {
      setEmployee(prev => ({
        ...prev,
        skills: [...prev.skills, newSkill],
        tempSkill: "",
        customSkill: ""
      }));
    }
  };

  const removeSkill = (skill) => {
    setEmployee(prev => ({
      ...prev,
      skills: prev.skills.filter(s => s !== skill)
    }));
  };

  /* SAVE */
  const handleAdd = (e) => {
    e.preventDefault();
    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const newEmployee = {
      id: Date.now(),
      name: `${employee.firstName} ${employee.lastName}`,
      ...employee
    };

    employees.push(newEmployee);
    localStorage.setItem("employees", JSON.stringify(employees));

    alert("Employee Added Successfully!");
    navigate("/dashboard/employee-details");
  };

  /* UPDATE */
  const handleUpdate = (e) => {
    e.preventDefault();
    let employees = JSON.parse(localStorage.getItem("employees")) || [];

    const updated = employees.map(emp =>
      String(emp.id) === String(id)
        ? {...emp, ...employee}
        : emp
    );

    localStorage.setItem("employees", JSON.stringify(updated));
    alert("Employee Updated Successfully!");
    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">

      <h2>{isEditMode ? "Edit Employee" : "Add Employee"}</h2>

      <div className="tabs">
        <button className={`tab ${activeTab==="personal"?"active":""}`} onClick={()=>setActiveTab("personal")}>PERSONAL</button>
        <button className={`tab ${activeTab==="employment"?"active":""}`} onClick={()=>setActiveTab("employment")}>EMPLOYMENT</button>
        <button className={`tab ${activeTab==="bank"?"active":""}`} onClick={()=>setActiveTab("bank")}>BANK</button>
        <button className={`tab ${activeTab==="education"?"active":""}`} onClick={()=>setActiveTab("education")}>EDUCATION</button>
      </div>

      <form className="employee-form" onSubmit={isEditMode?handleUpdate:handleAdd}>

        {/* PERSONAL */}
        {activeTab==="personal" && (
          <>
            <h3>Personal Details</h3>

            <div className="employee-grid">

              <input name="firstName" value={employee.firstName} placeholder="First Name" onChange={handleChange}/>
              <input name="lastName" value={employee.lastName} placeholder="Last Name" onChange={handleChange}/>
              <input name="empId" value={employee.empId} placeholder="Employee ID" onChange={handleChange}/>

              <select name="gender" value={employee.gender} onChange={handleChange}>
                <option value="">Gender</option>
                <option>Male</option>
                <option>Female</option>
              </select>

              <input type="date" name="dob" value={employee.dob} onChange={handleChange}/>
              <select name="maritalStatus" value={employee.maritalStatus} onChange={handleChange}>
                <option value="">Marital</option>
                <option>Single</option>
                <option>Married</option>
              </select>

              <input type="email" name="email" value={employee.email} placeholder="Email" onChange={handleChange}/>

              {/* NEW FIELDS */}
              <input name="aadhar" maxLength="12" placeholder="Aadhar Number" value={employee.aadhar} onChange={handleChange}/>
              <input name="pan" maxLength="10" placeholder="PAN Number"
                     value={employee.pan}
                     onChange={(e)=>setEmployee({...employee,pan:e.target.value.toUpperCase()})}/>

              <div style={{gridColumn:"1 / span 2"}}>
                <label>Upload Employee Documents</label>
                <input type="file" multiple onChange={(e)=>handleFileUpload(e,"employeeFiles")}/>
              </div>

            </div>
          </>
        )}

        {/* EMPLOYMENT */}
        {activeTab==="employment" && (
          <>
            <h3>Employment Details</h3>
            <div className="employee-grid">

              <select name="designation" value={employee.designation} onChange={handleChange}>
                <option value="">Designation</option>
                {designations.map(d=>(
                  <option key={d.id}>{d.title}</option>
                ))}
              </select>

              <input name="salary" value={employee.salary} placeholder="Salary" onChange={handleChange}/>

              <select name="department" value={employee.department} onChange={handleChange}>
                <option value="">Department</option>
                <option>Frontend</option>
                <option>Backend</option>
                <option>IT</option>
                <option>HR</option>
              </select>

              <select name="role" value={employee.role} onChange={handleChange}>
                <option value="">Role</option>
                <option>Employee</option>
                <option>Admin</option>
              </select>

              <select name="tempSkill" value={employee.tempSkill} onChange={handleChange}>
                <option value="">Skill</option>
                {skillOptions.map(s=><option key={s}>{s}</option>)}
                <option>Other</option>
              </select>

              {employee.tempSkill==="Other" &&
                <input name="customSkill" value={employee.customSkill} onChange={handleChange}/>
              }

              <button type="button" className="save-btn" onClick={addSkill}>
                Add Skill
              </button>

              <div style={{gridColumn:"1/span 2"}}>
                {employee.skills.map(skill=>(
                  <span key={skill} onClick={()=>removeSkill(skill)}>
                    {skill} ✖
                  </span>
                ))}
              </div>

            </div>
          </>
        )}

        {/* BANK */}
        {activeTab==="bank" && (
          <div className="employee-grid">
            <input name="bankName" value={employee.bankName} placeholder="Bank Name" onChange={handleChange}/>
            <input name="accountNumber" value={employee.accountNumber} placeholder="Account Number" onChange={handleChange}/>
            <input name="ifsc" value={employee.ifsc} placeholder="IFSC" onChange={handleChange}/>
          </div>
        )}

        {/* EDUCATION */}
        {activeTab==="education" && (
          <div className="employee-grid">

            <select name="qualification" value={employee.qualification} onChange={handleChange}>
              <option value="">Qualification</option>
              <option>B.Tech</option>
              <option>M.Tech</option>
              <option>MBA</option>
            </select>

            <input name="university" value={employee.university} placeholder="University" onChange={handleChange}/>
            <input name="passingYear" value={employee.passingYear} placeholder="Passing Year" onChange={handleChange}/>

            <div style={{gridColumn:"1/span 2"}}>
              <label>Upload Certificates</label>
              <input type="file" multiple onChange={(e)=>handleFileUpload(e,"certificates")}/>
            </div>

          </div>
        )}

        <button className="save-btn" type="submit">
          {isEditMode ? "Update Employee" : "Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
